// ═══════════════════════════════════════════════════════════════════
// دوال مساعدة لاسترجاع الأسئلة
// ═══════════════════════════════════════════════════════════════════

/**
 * استرجاع أسئلة بناءً على المعايير
 * @param {Object} filters - { level, category, type, count }
 * @returns {Array} مجموعة من الأسئلة المختارة عشوائياً
 */
window.getArenaQuestions = function(filters = {}) {
  const { level, category, type, count = 15 } = filters;
  
  let pool = [...window.ARENA_QUESTIONS];
  
  if (level) pool = pool.filter(q => q.level === level);
  if (category) pool = pool.filter(q => q.category === category);
  if (type) pool = pool.filter(q => q.type === type);
  
  // خلط عشوائي
  for (let i = pool.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [pool[i], pool[j]] = [pool[j], pool[i]];
  }
  
  // اختيار العدد المطلوب
  return pool.slice(0, count);
};

/**
 * الحصول على إحصائيات البنك
 */
window.getArenaStats = function() {
  const stats = {
    total: window.ARENA_QUESTIONS.length,
    byLevel: {},
    byCategory: {},
    byType: {}
  };
  
  window.ARENA_QUESTIONS.forEach(q => {
    stats.byLevel[q.level] = (stats.byLevel[q.level] || 0) + 1;
    stats.byCategory[q.category] = (stats.byCategory[q.category] || 0) + 1;
    stats.byType[q.type] = (stats.byType[q.type] || 0) + 1;
  });
  
  return stats;
};

console.log("✅ صراع الأبطال: تم تحميل " + window.ARENA_QUESTIONS.length + " سؤال");
